/**
 * The type of statistic to include or exclude in the summary statistics calculation.
 *
 * @since 5.0
 */
export type OutStatisticType = "avg" | "count" | "max" | "median" | "min" | "stddev" | "sum" | "variance" | "nullcount";

/** @since 5.0 */
export interface OutStatisticTypes {
  /**
   * The statistics to include in the calculation.
   *
   * @since 5.0
   */
  include?: OutStatisticType[];
  /**
   * The statistics to exclude from the calculation. Some statistics, such as `median`, are
   *   computationally expensive to calculate and may be excluded to improve performance.
   *
   * @since 5.0
   */
  exclude?: OutStatisticType[];
}